#script:
		public static Object fn(Dialog, PSFactory) throws Exception {
			dataplan.common.dialogs.dpQueryDialog dlg = new dataplan.common.dialogs.dpQueryDialog(Dialog, PSFactory);
			dlg.setVisible(true);
			//dlg.executeQuery("select * from dpUser", "");
			return null;
		}

#script:
		public static Object fn(Dialog) throws Exception {
			try {
				java.io.File f = dataplan.common.components.dpRemoteFileChooser.showOpenDialog(Dialog, "./");
				if(f != null && f.isFile()) {
					dataplan.common.utilities.dpSystemEnvironment.openFileWithExternalApplication(f.getCanonicalPath());
				}
				return f;
			} catch(Exception ex) {
				return ex;
			}
		}
